import anthropic, json

client = anthropic.Anthropic()

extract_tool = {
    "name": "extract_order",
    "description": "Extract structured order information from unstructured text.",
    "input_schema": {
        "type": "object",
        "properties": {
            "customer_name": {"type": "string"},
            "product_sku":   {"type": "string"},
            "quantity":      {"type": "integer", "minimum": 1},
            "priority":      {"type": "string", "enum": ["standard", "express", "overnight"]},
        },
        "required": ["customer_name", "product_sku", "quantity", "priority"],
    },
}

def extract_order(raw_text: str) -> dict:
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        temperature=0,
        tools=[extract_tool],
        tool_choice={"type": "tool", "name": "extract_order"},  # force tool use
        messages=[{"role": "user", "content": raw_text}],
    )
    for block in response.content:
        if block.type == "tool_use" and block.name == "extract_order":
            return block.input
    raise RuntimeError("Tool call missing from response")

order = extract_order(
    "Hi, Jane Smith needs 3 units of SKU-8821 shipped overnight please."
)
print(json.dumps(order, indent=2))
